/* ============================================================
   PRESET « ROYAL CONTINENT » v3 (Albion Online) — Bloxd Terrain Editor
   Monde 1602 x 1104 — 196 512 points (1 point / 3 blocs) — relief
   généré par le MOTEUR DU SITE. Demande la version >= 2.4 du site.

   v3 :
   - MONTAGNES MOINS HAUTES (pics ~140 au lieu de ~178) + zones de
     TOUNDRA : plateaux plats enneigés disséminés dans le massif nord
   - DESERT 100% SABLE : les poches d'herbe / forêt à l'intérieur du
     désert sont converties en sable (2 passes de nettoyage majoritaire)
   - (hérité v2) 1 point / 3 blocs + IDW corrigé -> export en petits
     blocs 1:1, pas de gros cubes.

   Régions : Sud=désert, Est=forêt, Sud-Ouest=forêt+plaine,
   Nord-Ouest=plaine, Nord/Nord-Est=neige+montagnes, lacs/océan.

   Installation :
   1. Ouvre l'application (index.html, version 2.3+)
   2. F12 -> onglet Console
   3. Colle TOUT ce fichier, Entrée
   4. La carte se charge immédiatement !
   ============================================================ */
(function () {
    var M = {"cols":534,"rows":368,"step":3,"worldX":1602,"worldZ":1104,"bio":["","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","",""],"dl":["","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","",""],"ds":["","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","",""]};

    var gen = window.generatorInstance;
    if (!gen) { alert("Ouvre d'abord l'application Bloxd Terrain Editor !"); return; }

    console.log('%c⏳ Génération du Royal Continent v3 (montagnes adoucies + toundra + désert 100% sable)...', 'color:#38bdf8');

    var SEED = 20260719;
    var noiseGen = new window.TerrainGenerator();
    noiseGen.initPermutationTable(SEED);
    var vn = function (x, z) { return noiseGen.valueNoise2D(x, z); };
    var smooth = function (t) { return t * t * (3 - 2 * t); };
    var B36 = '0123456789abcdefghijklmnopqrstuvwxyz';

    var SEA = 88, cols = M.cols, rows = M.rows, STEP = M.step;

    // --- 0. Nettoyage du désert : QUE du sable, pas d'herbe ---
    // Flood-fill : toute poche verte (plaine/forêt/marais) dont la
    // frontière terrestre est ENTIEREMENT du sable est convertie en sable.
    var bioArr = [];
    for (var cz = 0; cz < rows; cz++) bioArr[cz] = M.bio[cz].split('');
    var isGreen = function (c) { return c === 'p' || c === 'f' || c === 'w'; };
    var fillGreenPockets = function () {
        var seenFF = new Uint8Array(cols * rows);
        for (var fz = 0; fz < rows; fz++) {
            for (var fx = 0; fx < cols; fx++) {
                if (!isGreen(bioArr[fz][fx]) || seenFF[fz * cols + fx]) continue;
                var stack = [fz * cols + fx], comp = [];
                seenFF[fz * cols + fx] = 1;
                var sandB = 0, otherB = 0;
                while (stack.length) {
                    var id = stack.pop(); comp.push(id);
                    var z0 = (id / cols) | 0, x0 = id % cols;
                    for (var d4 = 0; d4 < 4; d4++) {
                        var az = z0 + (d4 === 0 ? 1 : d4 === 1 ? -1 : 0);
                        var ax = x0 + (d4 === 2 ? 1 : d4 === 3 ? -1 : 0);
                        if (az < 0 || az >= rows || ax < 0 || ax >= cols) continue;
                        var nb = bioArr[az][ax];
                        if (isGreen(nb)) {
                            var nid = az * cols + ax;
                            if (!seenFF[nid]) { seenFF[nid] = 1; stack.push(nid); }
                        } else if (nb === 's') sandB++;
                        else if (nb !== 'o') otherB++;
                    }
                }
                if (sandB > 0 && otherB === 0) {
                    for (var ci = 0; ci < comp.length; ci++)
                        bioArr[(comp[ci] / cols) | 0][comp[ci] % cols] = 's';
                }
            }
        }
    };
    fillGreenPockets();
    // + 1 passe majoritaire (rayon 3) pour gommer les franges d'herbe
    // qui mordent sur le bord du désert.
    var bioNew = [];
    for (cz = 0; cz < rows; cz++) {
        bioNew[cz] = bioArr[cz].slice();
        for (cx = 0; cx < cols; cx++) {
            if (!isGreen(bioArr[cz][cx])) continue;
            var sandN = 0, landN = 0;
            for (var dz0 = -3; dz0 <= 3; dz0++) {
                for (var dx0 = -3; dx0 <= 3; dx0++) {
                    var az0 = cz + dz0, ax0 = cx + dx0;
                    if (az0 < 0 || az0 >= rows || ax0 < 0 || ax0 >= cols) continue;
                    var nb2 = bioArr[az0][ax0];
                    if (nb2 === 'o') continue;
                    landN++;
                    if (nb2 === 's') sandN++;
                }
            }
            if (landN > 0 && sandN / landN > 0.5) bioNew[cz][cx] = 's';
        }
    }
    bioArr = bioNew;
    fillGreenPockets(); // re-nettoie les poches créées par la passe majoritaire

    // --- 1. Hauteurs : base par biome + fbm du site + rampes côtières ---
    var hmap = [], isSea = [], tmask = [];
    for (cz = 0; cz < rows; cz++) {
        hmap[cz] = []; isSea[cz] = []; tmask[cz] = [];
        var bioRow = bioArr[cz], dlRow = M.dl[cz], dsRow = M.ds[cz];
        for (cx = 0; cx < cols; cx++) {
            var b = bioRow[cx];
            tmask[cz][cx] = 0;
            var wx = cx * STEP - M.worldX / 2, wz = cz * STEP - M.worldZ / 2;
            var h;
            if (b === 'o') {
                var ds = B36.indexOf(dsRow[cx]);
                h = 86 - Math.min(ds * STEP / 5, 18) * 1.1 + (vn(wx * 0.02, wz * 0.02) - 0.5) * 3;
                if (h > SEA - 1) h = SEA - 1;
                isSea[cz][cx] = true;
            } else {
                var dl = B36.indexOf(dlRow[cx]);
                // distances en CHUNKS de grille -> converties en "unités v1" (5 blocs)
                var dlB = dl * STEP / 5;
                var t = smooth(Math.min(dlB, 8) / 8);
                var n1 = vn(wx * 0.008, wz * 0.008);
                var n2 = vn(wx * 0.0184 + 19.7, wz * 0.0184 - 41.2);
                var ridge = 1 - Math.abs(2 * n2 - 1);
                var n3 = vn(wx * 0.0408, wz * 0.0408);
                if (b === 's')      h = 91 + t * 5  + (n1 - 0.5) * 8  + ridge * 4 + (n3 - 0.5) * 2;
                else if (b === 'w') h = 90 + t * 2  + (n1 - 0.5) * 4  + (n3 - 0.5) * 2;
                else if (b === 'p') h = 93 + t * 6  + (n1 - 0.5) * 10 + ridge * 5 + (n3 - 0.5) * 3;
                else if (b === 'f') h = 96 + t * 9  + (n1 - 0.5) * 12 + ridge * 10 + (n3 - 0.5) * 4;
                else {
                    // v3 : massif nord MOINS HAUT (ridge 42 -> 24, base 106 -> 100)
                    h = 100 + t * 12 + (n1 - 0.5) * 14 + ridge * 24 + (n3 - 0.5) * 5;
                    // Zones de TOUNDRA : plateaux plats et bas, par endroits
                    var tu = (vn(wx * 0.006 + 31.4, wz * 0.006 - 12.8) - 0.50) / 0.18;
                    tu = tu < 0 ? 0 : (tu > 1 ? 1 : tu); tu = smooth(tu);
                    var hT = 103 + t * 3 + (n1 - 0.5) * 5 + (n3 - 0.5) * 2;
                    h = h + (hT - h) * tu;
                    tmask[cz][cx] = tu;
                }
                var shore = smooth(Math.min(dlB, 6) / 6);
                h = 89.5 + (h - 89.5) * (0.25 + 0.75 * shore);
                if (h < SEA + 1) h = SEA + 1;
                isSea[cz][cx] = false;
            }
            hmap[cz][cx] = h;
        }
    }

    // --- 2. Deux passes de lissage 3x3 (trait de côte figé) ---
    for (var pass = 0; pass < 2; pass++) {
        var nh = [];
        for (cz = 0; cz < rows; cz++) {
            nh[cz] = [];
            for (cx = 0; cx < cols; cx++) {
                var sum = 0, n = 0;
                for (var dz = -1; dz <= 1; dz++) {
                    for (var dx = -1; dx <= 1; dx++) {
                        var az = cz + dz, ax = cx + dx;
                        if (az < 0 || az >= rows || ax < 0 || ax >= cols) continue;
                        if (isSea[az][ax] !== isSea[cz][cx]) continue;
                        sum += hmap[az][ax]; n++;
                    }
                }
                nh[cz][cx] = sum / n;
            }
        }
        hmap = nh;
    }

    // --- 3. Édits (montagne/neige par altitude dans le massif nord) ---
    var edits = {};
    for (cz = 0; cz < rows; cz++) {
        for (cx = 0; cx < cols; cx++) {
            var b = bioArr[cz][cx];
            var hh = Math.round(hmap[cz][cx]);
            if (isSea[cz][cx] && hh > SEA) hh = SEA;
            if (!isSea[cz][cx] && hh <= SEA) hh = SEA + 1;
            var wx2 = cx * STEP - M.worldX / 2, wz2 = cz * STEP - M.worldZ / 2;
            var biome;
            if (b === 'o' || b === 's') biome = 'sand';
            else if (b === 'w' || b === 'p') biome = 'plain';
            else if (b === 'f') biome = 'forest';
            else {
                // v3 : snowline abaissée (montagnes moins hautes)
                var snowLine = 118 + (vn(wx2 * 0.01 + 7.7, wz2 * 0.01 + 3.3) - 0.5) * 14;
                if (tmask[cz][cx] > 0.5) biome = 'snow';               // toundra plate enneigée
                else if (b === 'n' && hh >= snowLine) biome = 'snow';  // sommets nord
                else if (hh >= snowLine + 10) biome = 'snow';          // calottes des pics
                else biome = 'mountain';
            }
            edits[wx2 + ',' + wz2] = { height: hh, biome: biome, half: STEP / 2 };
        }
    }

    var config = {
        worldSizeX: M.worldX, worldSizeZ: M.worldZ,
        viewportMode: 'global', gridResolution: 256,
        seed: SEED, baseY: 70, seaLevel: SEA,
        minHeight: 60, maxHeight: 160,
        noiseScale: 0.008, terrainIntensity: 10, roughness: 0.5,
        showWater: true, defaultBiome: 'plain', pixelatedExport: false
    };
    var preset = {
        name: '👑 Royal Continent v3 (Albion Online)',
        config: config,
        customEdits: edits
    };

    // --- 4. Application immédiate ---
    gen.saveStateForUndo && gen.saveStateForUndo();
    gen.presets['custom_royal_continent'] = preset;
    Object.assign(gen.config, config);
    gen.customEdits = new Map();
    for (var k in edits) gen.customEdits.set(k, edits[k]);
    gen._editIndexDirty = true;
    if (gen.invalidateDetailChunks) gen.invalidateDetailChunks();
    gen.generateGrid(false);
    if (window.map2dInstance) window.map2dInstance.render();
    if (window.map3dInstance) window.map3dInstance.updateTerrain();
    if (window.uiManagerInstance) {
        window.uiManagerInstance.syncUIWithConfig && window.uiManagerInstance.syncUIWithConfig();
        window.uiManagerInstance.updateStatsBar && window.uiManagerInstance.updateStatsBar();
    }
    var sel = document.getElementById('select-preset');
    if (sel && !sel.querySelector('option[value="custom_royal_continent"]')) {
        var opt = document.createElement('option');
        opt.value = 'custom_royal_continent';
        opt.textContent = '⭐ ' + preset.name;
        opt.selected = true;
        sel.appendChild(opt);
    }
    console.log('%c✓ Royal Continent v3 chargé (196k points — montagnes adoucies, toundra, désert 100% sable) !', 'color:#10b981;font-weight:bold');

    // --- 5. Persistance (peut échouer : 196k édits ~ 8 Mo > quota localStorage) ---
    try {
        var saved = JSON.parse(localStorage.getItem('bloxd_custom_presets') || '{}');
        for (var key in saved) {
            if (key.indexOf('albion') !== -1 || key.indexOf('royal') !== -1 ||
                (saved[key].name || '').indexOf('Albion') !== -1 || (saved[key].name || '').indexOf('Royal') !== -1) delete saved[key];
        }
        saved['custom_royal_continent'] = preset;
        localStorage.setItem('bloxd_custom_presets', JSON.stringify(saved));
        console.log('%c✓ Preset sauvegardé : disponible après rechargement.', 'color:#10b981');
    } catch (e) {
        console.warn('⚠️ Sauvegarde impossible (' + e.message + ') — NORMAL en haute densité.');
        console.warn('La carte est bien CHARGÉE : exporte ton .bloxdschem maintenant,');
        console.warn('ou recolle ce script après un rechargement de page.');
    }
})();
